using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers;

/// <summary>
/// Creates in-memory SchoolContext instances for unit testing.
/// Each call with a unique dbName produces an isolated database.
/// </summary>
public static class TestDbContextFactory
{
    public static SchoolContext Create(string dbName)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;

        return new SchoolContext(options);
    }

    /// <summary>
    /// Creates a context pre-seeded with standard test data.
    /// </summary>
    public static SchoolContext CreateSeeded(string dbName)
    {
        var context = Create(dbName);
        SeedTestData(context);
        return context;
    }

    public static void SeedTestData(SchoolContext context)
    {
        var students = new[]
        {
            new Student { ID = 1, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2010-09-01") },
            new Student { ID = 2, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2012-09-01") },
            new Student { ID = 3, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2013-09-01") },
        };
        context.Students.AddRange(students);

        var instructors = new[]
        {
            new Instructor { ID = 10, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") },
            new Instructor { ID = 11, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = DateTime.Parse("2002-07-06") },
        };
        context.Instructors.AddRange(instructors);

        var departments = new[]
        {
            new Department { DepartmentID = 1, Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 10 },
            new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = 11 },
        };
        context.Departments.AddRange(departments);

        var courses = new[]
        {
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
        };
        context.Courses.AddRange(courses);

        var enrollments = new[]
        {
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 1, CourseID = 4022, Grade = Grade.C },
            new Enrollment { EnrollmentID = 3, StudentID = 2, CourseID = 1050, Grade = Grade.B },
        };
        context.Enrollments.AddRange(enrollments);

        var courseAssignments = new[]
        {
            new CourseAssignment { CourseID = 1050, InstructorID = 10 },
            new CourseAssignment { CourseID = 4022, InstructorID = 11 },
        };
        context.CourseAssignments.AddRange(courseAssignments);

        var officeAssignments = new[]
        {
            new OfficeAssignment { InstructorID = 11, Location = "Smith 17" },
        };
        context.OfficeAssignments.AddRange(officeAssignments);

        context.SaveChanges();
    }
}

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    [DataRow(10, 1, 5, 2, DisplayName = "10 items, page 1, size 5 => 2 pages")]
    [DataRow(10, 2, 5, 2, DisplayName = "10 items, page 2, size 5 => 2 pages")]
    [DataRow(11, 1, 5, 3, DisplayName = "11 items, page 1, size 5 => 3 pages (ceiling)")]
    [DataRow(1, 1, 10, 1, DisplayName = "1 item, page 1, size 10 => 1 page")]
    [DataRow(0, 1, 10, 0, DisplayName = "0 items, page 1, size 10 => 0 pages")]
    public void Constructor_SetsCorrectTotalPages(int totalCount, int pageIndex, int pageSize, int expectedTotalPages)
    {
        var items = Enumerable.Range(0, Math.Min(totalCount, pageSize)).ToList();

        var sut = new PaginatedList<int>(items, totalCount, pageIndex, pageSize);

        Assert.AreEqual(expectedTotalPages, sut.TotalPages);
        Assert.AreEqual(pageIndex, sut.PageIndex);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var sut = new PaginatedList<string>(items, 10, 1, 3);

        Assert.AreEqual(3, sut.Count);
        CollectionAssert.AreEqual(items, sut.ToList());
    }

    [TestMethod]
    [DataRow(1, false, DisplayName = "Page 1 has no previous page")]
    [DataRow(2, true, DisplayName = "Page 2 has previous page")]
    [DataRow(3, true, DisplayName = "Page 3 has previous page")]
    public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
    {
        var sut = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

        Assert.AreEqual(expected, sut.HasPreviousPage);
    }

    [TestMethod]
    [DataRow(1, 3, true, DisplayName = "Page 1 of 3 has next page")]
    [DataRow(3, 3, false, DisplayName = "Page 3 of 3 has no next page")]
    [DataRow(2, 3, true, DisplayName = "Page 2 of 3 has next page")]
    public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
    {
        var totalCount = totalPages * 10;
        var sut = new PaginatedList<int>(new List<int>(), totalCount, pageIndex, 10);

        Assert.AreEqual(expected, sut.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(10, result.Count);
        Assert.AreEqual(11, result[0]); // second page starts at 11
        Assert.AreEqual(20, result[9]);
    }

    [TestMethod]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(21, result[0]);
        Assert.AreEqual(25, result[4]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    // Drain the static queue before each test to prevent cross-test interference
    [TestInitialize]
    public void DrainQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Student 'John Doe' has been created", DisplayName = "CREATE with display name")]
    [DataRow(EntityOperation.UPDATE, "Student 'John Doe' has been updated", DisplayName = "UPDATE with display name")]
    [DataRow(EntityOperation.DELETE, "Student 'John Doe' has been deleted", DisplayName = "DELETE with display name")]
    public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation op, string expectedMessage)
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "John Doe", op, "admin");

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual(op.ToString(), notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Course", "42", EntityOperation.CREATE);

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToApproximatelyNow()
    {
        using var sut = new NotificationService();
        var before = DateTime.Now.AddSeconds(-1);

        sut.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        using var sut = new NotificationService();

        var result = sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        using var sut = new NotificationService();

        sut.SendNotification("A", "1", EntityOperation.CREATE);
        sut.SendNotification("B", "2", EntityOperation.UPDATE);

        var first = sut.ReceiveNotification();
        var second = sut.ReceiveNotification();

        Assert.AreEqual("A", first!.EntityType);
        Assert.AreEqual("B", second!.EntityType);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        using var sut = new NotificationService();

        // MarkAsRead is a no-op, should not throw
        sut.MarkAsRead(1);
        sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var sut = new NotificationService();
        sut.Dispose();
        // Should be safe to call multiple times
        sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_ThreeParamOverload_DelegatesToFiveParam()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Dept", "5", EntityOperation.DELETE, "testuser");

        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Dept (ID: 5) has been deleted", notification.Message);
        Assert.AreEqual("testuser", notification.CreatedBy);
    }
}

