using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsAllData()
    {
        var context = TestDbContextFactory.Create(Guid.NewGuid().ToString());

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(5, context.Instructors.Count());
        Assert.AreEqual(4, context.Departments.Count());
        Assert.AreEqual(7, context.Courses.Count());
        Assert.AreEqual(3, context.OfficeAssignments.Count());
        Assert.AreEqual(8, context.CourseAssignments.Count());
        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicateData()
    {
        var context = TestDbContextFactory.Create(Guid.NewGuid().ToString());
        DbInitializer.Initialize(context);

        // Call again
        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.Students.Count());
        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentNames()
    {
        var context = TestDbContextFactory.Create(Guid.NewGuid().ToString());
        DbInitializer.Initialize(context);

        Assert.IsNotNull(context.Students.FirstOrDefault(s => s.LastName == "Alexander"));
        Assert.IsNotNull(context.Students.FirstOrDefault(s => s.LastName == "Alonso"));
        Assert.IsNotNull(context.Students.FirstOrDefault(s => s.LastName == "Olivetto"));
    }

    [TestMethod]
    public void Initialize_SeedsCorrectDepartmentsWithAdministrators()
    {
        var context = TestDbContextFactory.Create(Guid.NewGuid().ToString());
        DbInitializer.Initialize(context);

        var english = context.Departments.First(d => d.Name == "English");
        Assert.IsNotNull(english.InstructorID);

        var math = context.Departments.First(d => d.Name == "Mathematics");
        Assert.IsNotNull(math.InstructorID);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectCourseCredits()
    {
        var context = TestDbContextFactory.Create(Guid.NewGuid().ToString());
        DbInitializer.Initialize(context);

        var chemistry = context.Courses.First(c => c.Title == "Chemistry");
        Assert.AreEqual(3, chemistry.Credits);

        var calculus = context.Courses.First(c => c.Title == "Calculus");
        Assert.AreEqual(4, calculus.Credits);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        var context = TestDbContextFactory.Create(Guid.NewGuid().ToString());
        DbInitializer.Initialize(context);

        var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).ToList();
        Assert.IsTrue(enrollmentsWithGrades.Count > 0);

        // Anand's Chemistry enrollment has no grade
        var anand = context.Students.First(s => s.LastName == "Anand");
        var chemistry = context.Courses.First(c => c.Title == "Chemistry");
        var noGradeEnrollment = context.Enrollments
            .First(e => e.StudentID == anand.ID && e.CourseID == chemistry.CourseID);
        Assert.IsNull(noGradeEnrollment.Grade);
    }
}

