using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded(Guid.NewGuid().ToString());
        _sut = new StudentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_DefaultSort_ReturnsStudentsOrderedByLastName()
    {
        var result = _sut.Index(null, null, null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(3, model.Count);
        // Default sort is by LastName ascending
        Assert.AreEqual("Alexander", model[0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Anand", model[2].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_ReturnsStudentsDescending()
    {
        var result = _sut.Index("name_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.AreEqual("Anand", model![0].LastName);
        Assert.AreEqual("Alonso", model[1].LastName);
        Assert.AreEqual("Alexander", model[2].LastName);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        var result = _sut.Index("Date", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.IsTrue(model![0].EnrollmentDate <= model[1].EnrollmentDate);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        var result = _sut.Index("date_desc", null, null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.IsTrue(model![0].EnrollmentDate >= model[1].EnrollmentDate);
    }

    [TestMethod]
    public void Index_SearchByLastName_FiltersCorrectly()
    {
        var result = _sut.Index(null, null, "Alexander", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchByFirstName_FiltersCorrectly()
    {
        var result = _sut.Index(null, null, "Meredith", null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Alonso", model[0].LastName);
    }

    [TestMethod]
    public void Index_SearchString_ResetsToPage1()
    {
        var result = _sut.Index(null, null, "Alexander", 3) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model!.PageIndex);
    }

    [TestMethod]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        var result = _sut.Index(null, "Anand", null, null) as ViewResult;
        var model = result!.Model as PaginatedList<Student>;

        Assert.AreEqual(1, model!.Count);
        Assert.AreEqual("Anand", model[0].LastName);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        _sut.Index(null, null, null, null);

        Assert.AreEqual("name_desc", _sut.ViewBag.NameSortParm);
        Assert.AreEqual("Date", _sut.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithNameDescSort_SetsEmptyNameSortParm()
    {
        _sut.Index("name_desc", null, null, null);

        Assert.AreEqual("", _sut.ViewBag.NameSortParm);
    }

    [TestMethod]
    public void Index_WithDateSort_SetsDateDescSortParm()
    {
        _sut.Index("Date", null, null, null);

        Assert.AreEqual("date_desc", _sut.ViewBag.DateSortParm);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsStudent()
    {
        var result = _sut.Details(1) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual("Alexander", model.LastName);
    }

    [TestMethod]
    public void Details_ValidId_IncludesEnrollments()
    {
        var result = _sut.Details(1) as ViewResult;
        var model = result!.Model as Student;

        Assert.IsNotNull(model!.Enrollments);
        Assert.AreEqual(2, model.Enrollments.Count);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithStudentDefaultEnrollmentDate()
    {
        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        var result = _sut.Create(student);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_SavesStudentToDatabase()
    {
        var student = new Student
        {
            LastName = "New",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        _sut.Create(student);

        Assert.AreEqual(4, _context.Students.Count());
        Assert.IsNotNull(_context.Students.FirstOrDefault(s => s.LastName == "New"));
    }

    [TestMethod]
    public void Create_Post_MinValueEnrollmentDate_ReturnsViewWithError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _sut.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsFalse(_sut.ModelState.IsValid);
        Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_DateBelow1753_ReturnsViewWithError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _sut.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithStudent()
    {
        _sut.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2024, 1, 15)
        };

        var result = _sut.Create(student) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreSame(student, result.Model);
    }

    #endregion

    #region Edit

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        var result = _sut.Edit(1) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.AreEqual("Alexander", model!.LastName);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = _context.Students.Find(1)!;
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = 1,
            LastName = "UpdatedName",
            FirstMidName = "Carson",
            EnrollmentDate = new DateTime(2024, 1, 15)
