using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Rendering;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class CoursesControllerTests
{
    private SchoolContext _context = null!;
    private CoursesController _sut = null!;
    private Mock<IWebHostEnvironment> _envMock = null!;
    private Mock<ILogger<CoursesController>> _loggerMock = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded(Guid.NewGuid().ToString());
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _sut = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_ReturnsViewWithAllCourses()
    {
        var result = _sut.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Course>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsCourseWithDepartment()
    {
        var result = _sut.Details(1050) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.IsNotNull(model);
        Assert.AreEqual("Chemistry", model.Title);
        Assert.IsNotNull(model.Department);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
        Assert.IsInstanceOfType<Course>(result.Model);
    }

    [TestMethod]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _sut.Create(course, null!);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidCourse_SavesToDB()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        _sut.Create(course, null!);

        Assert.AreEqual(3, _context.Courses.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithCourse()
    {
        _sut.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 9999, Credits = 3, DepartmentID = 1 };

        var result = _sut.Create(course, null!) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreSame(course, result.Model);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    #endregion

    #region Edit

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _sut.Edit(1050) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.AreEqual("Chemistry", model!.Title);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    [TestMethod]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        var course = _context.Courses.Find(1050)!;
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedCourse = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 1
        };

        var result = _sut.Edit(updatedCourse, null!);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsViewWithCourse()
    {
        _sut.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, Credits = 3, DepartmentID = 1 };

        var result = _sut.Edit(course, null!) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.DepartmentID);
    }

    #endregion

    #region Delete

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _sut.Delete(1050) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Course;
        Assert.AreEqual("Chemistry", model!.Title);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        var result = _sut.DeleteConfirmed(1050);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.AreEqual(1, _context.Courses.Count());
    }

    #endregion
}

