using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class DepartmentsControllerTests
{
    private SchoolContext _context = null!;
    private DepartmentsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded(Guid.NewGuid().ToString());
        _sut = new DepartmentsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_ReturnsViewWithAllDepartments()
    {
        var result = _sut.Index() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as List<Department>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Details(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var result = _sut.Details(1) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("English", model!.Name);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new DateTime(2024, 1, 1),
            InstructorID = 10
        };

        var result = _sut.Create(department);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidDepartment_SavesIntoDB()
    {
        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new DateTime(2024, 1, 1),
            InstructorID = 10
        };

        _sut.Create(department);

        Assert.AreEqual(3, _context.Departments.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsViewWithDepartment()
    {
        _sut.ModelState.AddModelError("Name", "Required");
        var department = new Department { Budget = 200000, StartDate = DateTime.Now };

        var result = _sut.Create(department) as ViewResult;

        Assert.IsNotNull(result);
        Assert.AreSame(department, result.Model);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    #endregion

    #region Edit

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Edit(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Edit(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var result = _sut.Edit(1) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("English", model!.Name);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    [TestMethod]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = _context.Departments.Find(1)!;
        _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedDept = new Department
        {
            DepartmentID = 1,
            Name = "Updated English",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1),
            InstructorID = 10
        };

        var result = _sut.Edit(updatedDept);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Edit_Post_InvalidModelState_ReturnsViewWithDepartment()
    {
        _sut.ModelState.AddModelError("Name", "Required");
        var department = new Department
        {
            DepartmentID = 1,
            Budget = 200000,
            StartDate = DateTime.Now,
            InstructorID = 10
        };

        var result = _sut.Edit(department) as ViewResult;

        Assert.IsNotNull(result);
        Assert.IsNotNull(_sut.ViewBag.InstructorID);
    }

    #endregion

    #region Delete

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _sut.Delete(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Delete(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        var result = _sut.Delete(1) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Department;
        Assert.AreEqual("English", model!.Name);
    }

    [TestMethod]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var result = _sut.DeleteConfirmed(1);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
        Assert.AreEqual(1, _context.Departments.Count());
    }

    #endregion
}

