using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private SchoolContext _context = null!;
    private InstructorsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded(Guid.NewGuid().ToString());
        _sut = new InstructorsController(_context);
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    #region Index

    [TestMethod]
    public void Index_NoParams_ReturnsViewWithAllInstructors()
    {
        var result = _sut.Index(null, null) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        var result = _sut.Index(10, null) as ViewResult;
        var model = result!.Model as InstructorIndexData;

        Assert.IsNotNull(model!.Courses);
        Assert.IsTrue(model.Courses.Any());
    }

    [TestMethod]
    public void Index_WithInstructorIdAndCourseId_PopulatesEnrollments()
    {
        var result = _sut.Index(10, 1050) as ViewResult;
        var model = result!.Model as InstructorIndexData;

        Assert.IsNotNull(model!.Enrollments);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _sut.Details(null);

        Assert.IsInstanceOfType<StatusCodeResult>(result);
        Assert.AreEqual(400, ((StatusCodeResult)result).StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _sut.Details(999);

        Assert.IsInstanceOfType<NotFoundResult>(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        var result = _sut.Details(10) as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.AreEqual("Abercrombie", model!.LastName);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithCoursesInViewBag()
    {
        var result = _sut.Create() as ViewResult;

        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(_sut.ViewBag.Courses);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1)
        };

        var result = _sut.Create(instructor, null!);

        Assert.IsInstanceOfType<RedirectToActionResult>(result);
        Assert.AreEqual("Index", ((RedirectToActionResult)result).ActionName);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_SavesToDB()
    {
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1)
        };

        _sut.Create(instructor, null!);

        Assert.AreEqual(3, _context.Instructors.Count());
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        var instructor = new Instructor
        {
