using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _sut = null!;

    [TestInitialize]
    public void Setup()
    {
        _context = TestDbContextFactory.CreateSeeded(Guid.NewGuid().ToString());
        _sut = new NotificationsController(_context);

        // Drain shared notification queue
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        var result = _sut.GetNotifications();

        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsUpTo10()
    {
        // Enqueue some notifications via the notification service
        var svc = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        var result = _sut.GetNotifications();

        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void MarkAsRead_ReturnsJsonResult()
    {
        var result = _sut.MarkAsRead(1);

        Assert.IsInstanceOfType<JsonResult>(result);
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        var result = _sut.Index();

        Assert.IsInstanceOfType<ViewResult>(result);
    }
}

