    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "John Doe", EntityOperation.DELETE, "admin");

        var notification = DrainUntilMatch(sut, "Student", "1");
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student 'John Doe' has been deleted", notification.Message);
        Assert.AreEqual("DELETE", notification.Operation);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Course", "42", EntityOperation.CREATE);

        var notification = DrainUntilMatch(sut, "Course", "42");
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course (ID: 42) has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Student", "1", "Test", EntityOperation.CREATE);

        var notification = DrainUntilMatch(sut, "Student", "1");
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToApproximatelyNow()
    {
        using var sut = new NotificationService();
        var before = DateTime.Now.AddSeconds(-1);

        sut.SendNotification("TimingTest", "1", EntityOperation.CREATE);

        var notification = DrainUntilMatch(sut, "TimingTest", "1");
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before);
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        using var sut = new NotificationService();
        // Drain everything first
        while (sut.ReceiveNotification() != null) { }

        var result = sut.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsInFifoOrder()
    {
        using var sut = new NotificationService();

        sut.SendNotification("FifoA", "1", EntityOperation.CREATE);
        sut.SendNotification("FifoB", "2", EntityOperation.UPDATE);

        var first = DrainUntilMatch(sut, "FifoA", "1");
        var second = DrainUntilMatch(sut, "FifoB", "2");

        Assert.IsNotNull(first);
        Assert.IsNotNull(second);
        Assert.AreEqual("FifoA", first.EntityType);
        Assert.AreEqual("FifoB", second.EntityType);
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        using var sut = new NotificationService();

        // MarkAsRead is a no-op, should not throw
        sut.MarkAsRead(1);
        sut.MarkAsRead(999);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        var sut = new NotificationService();
        sut.Dispose();
        // Should be safe to call multiple times
        sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_ThreeParamOverload_DelegatesToFiveParam()
    {
        using var sut = new NotificationService();

        sut.SendNotification("Dept", "5", EntityOperation.DELETE, "testuser");

        var notification = DrainUntilMatch(sut, "Dept", "5");
        Assert.IsNotNull(notification);
        Assert.AreEqual("Dept (ID: 5) has been deleted", notification.Message);
        Assert.AreEqual("testuser", notification.CreatedBy);
    }

    /// <summary>
    /// Drains the queue until a notification matching entityType and entityId is found.
    /// This handles residual notifications from other tests that share the static queue.
    /// </summary>
    private static Notification? DrainUntilMatch(NotificationService svc, string entityType, string entityId)
    {
        for (int i = 0; i < 1000; i++)
        {
            var n = svc.ReceiveNotification();
            if (n == null) return null;
            if (n.EntityType == entityType && n.EntityId == entityId) return n;
        }
        return null;
    }
}

