+    /// <summary>
+    /// Drains the queue until a notification matching entityType and entityId is found.
+    /// This handles residual notifications from other tests that share the static queue.
+    /// </summary>
+    private static Notification? DrainUntilMatch(NotificationService svc, string entityType, string entityId)
+    {
+        for (int i = 0; i < 1000; i++)
+        {
+            var n = svc.ReceiveNotification();
+            if (n == null) return null;
+            if (n.EntityType == entityType && n.EntityId == entityId) return n;
+        }
